import { _ as _export_sfc } from "./plugin-vue_export-helper.1tPrXgE0.js";
const __pageData = JSON.parse('{"title":"Domaines, site web et boite de reception","description":"","frontmatter":{"title":"Domaines, site web et boite de reception","last_verified":"2026-05-09T00:00:00.000Z"},"headers":[],"relativePath":"fr/features/domains-website-inbox.md","filePath":"fr/features/domains-website-inbox.md"}');
